#include <iostream>
using namespace std;

int main() {
    int scores[6] = {85, 90, 78, 92, 88, 95};
    int n = 6;

    // Calculate sum using expression in loop
    int sum = 0;
    for (int i = 0; i < n; i++) {
        sum += scores[i];  // Compound assignment expression
    }

    // Calculate average using arithmetic expression
    float average = (float)sum / n;

    // Count elements above average using relational expression
    int countAbove = 0;
    for (int i = 0; i < n; i++) {
        if (scores[i] > average) {
            countAbove++;
        }
    }

    // Find maximum using conditional expression
    int maxScore = scores[0];
    for (int i = 1; i < n; i++) {
        maxScore = (scores[i] > maxScore) ? scores[i] : maxScore;
    }

    cout << "Sum: " << sum << endl;
    cout << "Average: " << average << endl;
    cout << "Count above average: " << countAbove << endl;
    cout << "Maximum score: " << maxScore << endl;

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    // 3x3 Matrix initialization
    int matrix[3][3] = {
        {1, 2, 3},
        {4, 5, 6},
        {7, 8, 9}
    };

    // Calculate diagonal sum using expressions
    int primaryDiagSum = 0;
    int secondaryDiagSum = 0;

    for (int i = 0; i < 3; i++) {
        primaryDiagSum += matrix[i][i];  // Primary diagonal: matrix[0][0], matrix[1][1], matrix[2][2]
        secondaryDiagSum += matrix[i][2 - i];  // Secondary diagonal: matrix[0][2], matrix[1][1], matrix[2][0]
    }

    // Find row sums and column sums using nested expressions
    int rowSum[3] = {0}, colSum[3] = {0};

    for (int i = 0; i < 3; i++) {
        for (int j = 0; j < 3; j++) {
            rowSum[i] += matrix[i][j];
            colSum[j] += matrix[i][j];
        }
    }

    // Count even and odd elements using logical AND expression
    int evenCount = 0, oddCount = 0;
    for (int i = 0; i < 3; i++) {
        for (int j = 0; j < 3; j++) {
            if ((matrix[i][j] % 2 == 0) && (matrix[i][j] > 0)) {
                evenCount++;
            } else {
                oddCount++;
            }
        }
    }

    // Display results
    cout << "Primary diagonal sum: " << primaryDiagSum << endl;
    cout << "Secondary diagonal sum: " << secondaryDiagSum << endl;

    cout << "Row sums: ";
    for (int i = 0; i < 3; i++) cout << rowSum[i] << " ";
    cout << endl;

    cout << "Column sums: ";
    for (int i = 0; i < 3; i++) cout << colSum[i] << " ";
    cout << endl;

    cout << "Even elements: " << evenCount << ", Odd elements: " << oddCount << endl;

    return 0;
}
